// ═══════════════════════════════════════════════════════════════
// T-01 REMEDIATION: Three-layer mandatory authentication
//   Layer 1: API key (X-Api-Key header vs TWC_API_KEY env)
//   Layer 2: HMAC-SHA256 body signature (mandatory)
//   Layer 3: CORS origin restriction (handled at webhook level)
// T-09 REMEDIATION: CORS allowedOrigins set on webhook node
// All three layers must pass. No optional modes.
// ═══════════════════════════════════════════════════════════════
const crypto = require('crypto');

const raw = $input.first().json;
const headers = raw.headers || {};

// ── Layer 1: API Key Gate ──
const apiKey = headers['x-api-key'] || headers['X-Api-Key'] || '';
const VALID_API_KEY = $env.TWC_API_KEY || '';

if (!VALID_API_KEY) {
  throw new Error('SERVER_CONFIG_ERROR: TWC_API_KEY environment variable not set.');
}
if (!apiKey || apiKey !== VALID_API_KEY) {
  throw new Error('AUTH_FAILED: Invalid or missing API key.');
}

// ── Layer 2: HMAC-SHA256 Signature Verification (MANDATORY) ──
const HMAC_SECRET = $env.TWC_HMAC_SECRET || '';
if (!HMAC_SECRET) {
  throw new Error('SERVER_CONFIG_ERROR: TWC_HMAC_SECRET environment variable not set.');
}

const signature = headers['x-hmac-signature'] || headers['X-Hmac-Signature'] || '';
if (!signature) {
  throw new Error('AUTH_FAILED: Missing HMAC signature. X-Hmac-Signature header required.');
}

const bodyStr = typeof raw.body === 'string' ? raw.body : JSON.stringify(raw.body || {});
const expected = crypto.createHmac('sha256', HMAC_SECRET).update(bodyStr).digest('hex');

// Timing-safe comparison to prevent side-channel attacks
let sigBuffer, expBuffer;
try {
  sigBuffer = Buffer.from(signature, 'hex');
  expBuffer = Buffer.from(expected, 'hex');
} catch (e) {
  throw new Error('AUTH_FAILED: Malformed HMAC signature.');
}
if (sigBuffer.length !== expBuffer.length || !crypto.timingSafeEqual(sigBuffer, expBuffer)) {
  throw new Error('AUTH_FAILED: HMAC signature mismatch.');
}

// ── Pass through authenticated payload ──
return [{ json: { ...raw, _authenticated: true, _auth_method: 'apikey+hmac', _auth_timestamp: new Date().toISOString() } }];

// ═══════════════════════════════════════════════════════════════
// T-04 REMEDIATION: Per-client sliding-window rate limiting
// T-07 PARTIAL: Caps max cities before fan-out amplification
// ═══════════════════════════════════════════════════════════════

// n8n static data persists across executions within the same worker
const $static = $getWorkflowStaticData('global');
if (!$static.requestLog) $static.requestLog = [];

const now = Date.now();
const WINDOW_MS = 60 * 1000;       // 1-minute sliding window
const MAX_REQUESTS = 10;            // max 10 requests per window
const MAX_CITIES_PER_REQUEST = 4;   // cap fan-out amplification

// ── Purge expired entries ──
$static.requestLog = $static.requestLog.filter(ts => now - ts < WINDOW_MS);

// ── Check limit ──
if ($static.requestLog.length >= MAX_REQUESTS) {
  throw new Error('RATE_LIMITED: Too many requests. Max ' + MAX_REQUESTS + ' per minute.');
}

// ── Record this request ──
$static.requestLog.push(now);

// ── Pre-check cities count for fan-out cap ──
const body = $input.first().json.body || $input.first().json;
let cities = body.cities;
if (typeof cities === 'string') {
  try { cities = JSON.parse(cities); } catch(e) { cities = [cities]; }
}
if (Array.isArray(cities) && cities.length > MAX_CITIES_PER_REQUEST) {
  throw new Error('INPUT_ERROR: Maximum ' + MAX_CITIES_PER_REQUEST + ' cities per request. Received: ' + cities.length);
}

return $input.all();

// ═══════════════════════════════════════════════════════════════
// T-03 REMEDIATION: Strict input validation, regex on travel_date,
//                   string length caps, no passthrough of raw fields
// T-06 REMEDIATION: Cryptographic request IDs via randomUUID()
// T-07 REMEDIATION: Explicit array length cap + string size limits
// T-12 REMEDIATION: All timestamps in UTC, no timezone exposure
// ═══════════════════════════════════════════════════════════════
const crypto = require('crypto');

const raw = $input.first().json;
const body = raw.body || raw;

// ── Constants ──
const MAX_STRING_LENGTH = 64;
const MAX_CITIES = 4;
const SUPPORTED = ['Austin','Miami','Denver','Chicago','New Orleans','San Francisco','Nashville'];
const ORIGIN_MAP = { NYC:'from_NYC', LA:'from_LA', CHICAGO:'from_Chicago', AUSTIN:'from_Austin', MIAMI:'from_Miami', DENVER:'from_Denver' };
const DATE_REGEX = /^\d{4}-(0[1-9]|1[0-2])-(0[1-9]|[12]\d|3[01])$/;

// ── Sanitize helper: strip to safe chars, cap length ──
function sanitize(val, maxLen) {
  if (typeof val !== 'string') return '';
  return val.replace(/[^a-zA-Z0-9\s\-_.]/g, '').substring(0, maxLen || MAX_STRING_LENGTH).trim();
}

// ── Parse cities ──
let cities = body.cities;
if (typeof cities === 'string') {
  try { cities = JSON.parse(cities); } catch(e) { cities = [cities]; }
}
if (!Array.isArray(cities) || cities.length === 0) {
  throw new Error('INPUT_ERROR: cities must be a non-empty array.');
}
if (cities.length > MAX_CITIES) {
  throw new Error('INPUT_ERROR: Maximum ' + MAX_CITIES + ' cities. Received: ' + cities.length);
}

// ── Validate each city against whitelist ──
const normalize = s => sanitize(s, 32).replace(/\w\S*/g, t => t.charAt(0).toUpperCase() + t.slice(1).toLowerCase());
const normalizedCities = cities.map(normalize);
const bad = normalizedCities.filter(c => !SUPPORTED.includes(c));
if (bad.length) throw new Error('INPUT_ERROR: Unsupported cities: ' + bad.join(', '));

// ── Validate origin against whitelist ──
const originRaw = sanitize(body.origin || '', 32);
const originKey = originRaw.toUpperCase().replace(/\s+/g, '_');
const originLookup = ORIGIN_MAP[originKey];
if (!originLookup) throw new Error('INPUT_ERROR: Unsupported origin.');

// ── Validate travel_date with strict regex ──
let travelDate = null;
if (body.travel_date) {
  const dateStr = sanitize(String(body.travel_date), 10);
  if (!DATE_REGEX.test(dateStr)) {
    throw new Error('INPUT_ERROR: travel_date must be YYYY-MM-DD format.');
  }
  // Additional: ensure it parses to a real date
  const parsed = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(parsed.getTime())) {
    throw new Error('INPUT_ERROR: travel_date is not a valid calendar date.');
  }
  travelDate = dateStr;
}

// ── Parse budget_mode strictly ──
let budgetMode = false;
if (typeof body.budget_mode === 'boolean') budgetMode = body.budget_mode;
else if (typeof body.budget_mode === 'string') budgetMode = body.budget_mode.toLowerCase() === 'true';

// ── Cryptographic request ID (T-06) ──
const requestId = 'TWC-' + crypto.randomUUID();

// ── Return only validated, sanitized fields — no raw passthrough ──
return [{ json: {
  cities: normalizedCities,
  origin: originRaw,
  origin_key: originLookup,
  travel_date: travelDate,
  budget_mode: budgetMode,
  request_id: requestId,
  timestamp: new Date().toISOString()  // UTC, no timezone leak
}}];

const input = $input.first().json;
return input.cities.map(city => ({ json: {
  city,
  origin: input.origin,
  origin_key: input.origin_key,
  travel_date: input.travel_date,
  budget_mode: input.budget_mode,
  request_id: input.request_id
}}));

// ═══════════════════════════════════════════════════════════════
// T-08 REMEDIATION: Propagates degradation flags per city
// ═══════════════════════════════════════════════════════════════
const all = $input.all().map(i => i.json);
const wMap = {}, tMap = {};
for (const item of all) {
  if (!item.city) continue;
  if (item.weather_score !== undefined || item.current !== undefined) wMap[item.city] = item;
  if (item.flight_cost !== undefined || item.total_daily_cost !== undefined) tMap[item.city] = item;
}
const cities = [...new Set([...Object.keys(wMap), ...Object.keys(tMap)])];
const degradations = [];
const unified = cities.map(city => {
  const w = wMap[city] || {};
  const t = tMap[city] || {};
  // Track degradation per city per domain
  if (w.data_degraded) degradations.push({ city, domain: 'weather', reason: w.degradation_reason });
  if (t.data_degraded) degradations.push({ city, domain: 'travel', reason: t.degradation_reason });
  return {
    city,
    request_id: w.request_id || t.request_id,
    origin: w.origin || t.origin,
    budget_mode: w.budget_mode || t.budget_mode || false,
    travel_date: w.travel_date || t.travel_date,
    weather: {
      source: w.source || 'unknown',
      temp_f: w.current?.temp_f || null,
      condition: w.current?.condition || 'Unknown',
      humidity: w.current?.humidity || null,
      avg_high: w.forecast_7day?.avg_high || null,
      precip_chance: w.forecast_7day?.precip_chance || null,
      alerts: w.alerts || [],
      weather_score: w.weather_score || 50
    },
    travel: {
      source: t.source || 'unknown',
      flight_cost: t.flight_cost || null,
      hotel_per_night: t.hotel_per_night || null,
      total_daily_cost: t.total_daily_cost || null,
      travel_hours: t.travel_hours || null,
      warnings: t.warnings || [],
      peak_season: t.peak_season || false
    }
  };
});
return [{ json: {
  cities: unified,
  degradations,
  any_degraded: degradations.length > 0,
  aggregated_at: new Date().toISOString()
} }];

const { cities, degradations, any_degraded, aggregated_at } = $input.first().json;
const budgetMode = cities[0]?.budget_mode || false;
const WEIGHTS = budgetMode
  ? { weather:0.15, cost:0.55, events:0.20, convenience:0.10 }
  : { weather:0.35, cost:0.30, events:0.20, convenience:0.15 };

function costScore(data) {
  const costs = data.map(c => c.travel.total_daily_cost).filter(x => x !== null);
  if (!costs.length) return data.map(() => 50);
  const max = Math.max(...costs), min = Math.min(...costs), range = max - min || 1;
  return data.map(c => c.travel.total_daily_cost === null ? 50 : Math.round(100 - ((c.travel.total_daily_cost - min) / range) * 100));
}

function convScore(data) {
  const times = data.map(c => c.travel.travel_hours).filter(x => x !== null);
  if (!times.length) return data.map(() => 50);
  const max = Math.max(...times), min = Math.min(...times), range = max - min || 1;
  return data.map(c => c.travel.travel_hours === null ? 50 : Math.round(100 - ((c.travel.travel_hours - min) / range) * 100));
}

function eventPenalty(warnings) {
  let p = 0;
  for (const w of warnings) {
    const wl = w.toLowerCase();
    if (wl.includes('extreme') || wl.includes('3x')) p += 30;
    else if (wl.includes('high') || wl.includes('surge') || wl.includes('2x') || wl.includes('inflated')) p += 20;
    else if (wl.includes('crowded') || wl.includes('peak')) p += 10;
    else p += 5;
  }
  return Math.min(p, 40);
}

const cs = costScore(cities);
const vs = convScore(cities);
const round1 = cities.map((c, i) => ({
  city: c.city,
  weather_score: c.weather.weather_score,
  cost_score: cs[i],
  event_penalty: eventPenalty(c.travel.warnings),
  convenience_score: vs[i]
}));
const bestWeather = [...round1].sort((a,b) => b.weather_score - a.weather_score)[0].city;
const bestCost = [...round1].sort((a,b) => b.cost_score - a.cost_score)[0].city;
const hasConflict = bestWeather !== bestCost;
const log = [
  '=== ROUND 1: DOMAIN SCORING ===',
  'Weather: ' + round1.map(r => r.city + '=' + r.weather_score).join(', '),
  'Cost:    ' + round1.map(r => r.city + '=' + r.cost_score).join(', '),
  '',
  '=== ROUND 2: CONFLICT DETECTION ===',
  'Weather recommends: ' + bestWeather,
  'Travel recommends:  ' + bestCost,
  hasConflict ? 'CONFLICT — applying weighted scoring.' : 'AGREEMENT — proceeding.'
].join('\n');
return [{ json: { cities, degradations, any_degraded, aggregated_at, round1, hasConflict, WEIGHTS, round1_log: log } }];

const { cities, degradations, any_degraded, aggregated_at, round1, hasConflict, WEIGHTS, round1_log } = $input.first().json;
const scored = cities.map((c, i) => {
  const r = round1[i];
  const eventScore = Math.max(0, 100 - r.event_penalty);
  const final = Math.round(
    r.weather_score * WEIGHTS.weather +
    r.cost_score * WEIGHTS.cost +
    eventScore * WEIGHTS.events +
    r.convenience_score * WEIGHTS.convenience
  );
  return { ...c, scores: { ...r, event_score: eventScore, final_score: final } };
});
const ranked = [...scored].sort((a,b) => b.scores.final_score - a.scores.final_score);
const winner = ranked[0];

function rationale(c) {
  const parts = [];
  if (c.weather.weather_score >= 80) parts.push(c.city + ' has excellent weather (' + c.weather.temp_f + 'F, ' + c.weather.condition + ')');
  else if (c.weather.weather_score >= 60) parts.push(c.city + ' has acceptable weather (' + c.weather.temp_f + 'F)');
  else parts.push(c.city + ' has poor weather (' + c.weather.temp_f + 'F, ' + c.weather.condition + ')');
  if (c.travel.total_daily_cost) parts.push('daily cost $' + c.travel.total_daily_cost + ' (flight $' + c.travel.flight_cost + ' + hotel $' + c.travel.hotel_per_night + ')');
  if (c.travel.warnings.length) parts.push('NOTE: ' + c.travel.warnings.join('; '));
  else parts.push('no major events');
  return parts.join('. ') + '.';
}

const round3_log = [
  '', '=== ROUND 3: WEIGHTED SCORES ===',
  'Weights: W=' + (WEIGHTS.weather*100) + '% C=' + (WEIGHTS.cost*100) + '% E=' + (WEIGHTS.events*100) + '% Conv=' + (WEIGHTS.convenience*100) + '%',
  ...ranked.map((c,i) => '#'+(i+1)+' '+c.city+': '+c.scores.final_score+' pts')
].join('\n');

return [{ json: {
  request_id: cities[0]?.request_id,
  degradations,
  any_degraded,
  recommendation: {
    winner: winner.city,
    final_score: winner.scores.final_score,
    rationale: rationale(winner),
    consensus: !hasConflict,
    mode: WEIGHTS.weather === 0.15 ? 'budget' : 'standard'
  },
  ranked_cities: ranked.map((c,i) => ({
    rank: i+1,
    city: c.city,
    final_score: c.scores.final_score,
    weather_source: c.weather.source,
    travel_source: c.travel.source,
    weather_summary: c.weather.temp_f + 'F, ' + c.weather.condition,
    cost_summary: '$' + c.travel.total_daily_cost + '/day',
    travel_time: c.travel.travel_hours + 'h',
    warnings: c.travel.warnings,
    score_breakdown: c.scores
  })),
  negotiation_log: round1_log + round3_log,
  weights_used: WEIGHTS,
  aggregated_at,
  completed_at: new Date().toISOString()
}}];

// ═══════════════════════════════════════════════════════════════
// T-05 REMEDIATION: No internal architecture details in response
// T-08 REMEDIATION: Degradation warnings prominently surfaced
// T-11 REMEDIATION: Response excludes raw negotiation log to
//                   minimize sensitive data in execution history
// ═══════════════════════════════════════════════════════════════
const {
  recommendation, ranked_cities, negotiation_log, weights_used,
  request_id, completed_at, degradations, any_degraded
} = $input.first().json;

// ── Build human-readable summary ──
const lines = [
  'RECOMMENDATION: ' + recommendation.winner,
  'Score: ' + recommendation.final_score + '/100 | Mode: ' + recommendation.mode.toUpperCase() +
    ' | Consensus: ' + (recommendation.consensus ? 'YES' : 'NO — coordinator resolved'),
  recommendation.rationale
];

// ── Prominent degradation warning ──
if (any_degraded) {
  lines.push('');
  lines.push('⚠ DATA QUALITY WARNING: Some results used fallback data.');
  for (const d of degradations) {
    lines.push('  → ' + d.city + ' [' + d.domain + ']: ' + d.reason);
  }
}

lines.push('');
lines.push('RANKINGS:');
for (const c of ranked_cities) {
  let line = '#' + c.rank + ' ' + c.city + ' — ' + c.final_score + '/100 | ' +
    c.weather_summary + ' | ' + c.cost_summary + ' | ' + c.travel_time;
  if (c.weather_source === 'MOCK_FALLBACK' || c.travel_source === 'MOCK_FALLBACK') {
    line += ' | ⚠ FALLBACK DATA';
  }
  if (c.warnings.length) line += ' | NOTE: ' + c.warnings.join(', ');
  lines.push(line);
}

lines.push('');
lines.push('WEIGHTS: Weather ' + (weights_used.weather*100) + '% | Cost ' +
  (weights_used.cost*100) + '% | Events ' + (weights_used.events*100) +
  '% | Convenience ' + (weights_used.convenience*100) + '%');

return [{ json: {
  success: true,
  request_id,
  data_quality: {
    all_live: !any_degraded,
    degradations: degradations || [],
    warning: any_degraded ? 'One or more data sources used fallback data. Results may not reflect current conditions.' : null
  },
  recommendation,
  ranked_cities,
  summary: lines.join('\n'),
  metadata: {
    weights_used,
    completed_at,
    workflow: 'Travel Weather Comparator v2.0 (Hardened)'
  }
  // NOTE: negotiation_log intentionally excluded from external response (T-11)
}}];

// ═══════════════════════════════════════════════════════════════
// T-05 REMEDIATION: Generic error response — NO internal details,
//                   NO port numbers, NO service names, NO hints.
//                   Correlation via request_id only.
// ═══════════════════════════════════════════════════════════════
const crypto = require('crypto');
const e = $input.first();
const internalMsg = e?.json?.error?.message || e?.error?.message || 'Unknown error';

// ── Classify error for external consumer (no internals leaked) ──
let externalCode = 'INTERNAL_ERROR';
let statusHint = 500;
if (internalMsg.includes('AUTH_FAILED')) { externalCode = 'UNAUTHORIZED'; statusHint = 401; }
else if (internalMsg.includes('RATE_LIMITED')) { externalCode = 'RATE_LIMITED'; statusHint = 429; }
else if (internalMsg.includes('INPUT_ERROR')) { externalCode = 'BAD_REQUEST'; statusHint = 400; }
else if (internalMsg.includes('SERVER_CONFIG_ERROR')) { externalCode = 'SERVICE_UNAVAILABLE'; statusHint = 503; }

// ── Generate error correlation ID ──
const errorId = 'ERR-' + crypto.randomUUID();

// ── Log full details server-side (visible in n8n execution log) ──
console.error(JSON.stringify({
  error_id: errorId,
  internal_message: internalMsg,
  timestamp: new Date().toISOString(),
  stack: e?.json?.error?.stack || null
}));

// ── Return sanitized response ──
return [{ json: {
  success: false,
  error: {
    code: externalCode,
    message: externalCode === 'BAD_REQUEST'
      ? internalMsg.replace('INPUT_ERROR: ', '')
      : 'An error occurred processing your request.',
    error_id: errorId,
    timestamp: new Date().toISOString()
  }
  // NO hint field. NO port numbers. NO service names.
}}];
